pub type UserRow = (i64, String, String, bool);

impl User {
    pub fn new(name: String, email: String) -> Self {
        User { id: 0, name, email, active: true }
    }

    pub fn to_row(&self) -> UserRow {
        (self.id, self.name.clone(), self.email.clone(), self.active)
    }

    pub fn from_row(row: UserRow) -> Self {
        User {
            id: row.0,
            name: row.1,
            email: row.2,
            active: row.3,
        }
    }
}

