#[test]
fn test_user_to_row() {
    let user = User { id: 1, name: "Bob".to_string(), email: "bob@test.com".to_string(), active: true };
    let row = user.to_row();
    assert_eq!(row.0, 1);
    assert_eq!(row.1, "Bob");
    assert_eq!(row.2, "bob@test.com");
    assert_eq!(row.3, true);
}

#[test]
fn test_user_from_row() {
    let row = (5, "Carol".to_string(), "carol@test.com".to_string(), false);
    let user = User::from_row(row);
    assert_eq!(user.id, 5);
    assert_eq!(user.name, "Carol");
    assert!(!user.active);
}

#[test]
fn test_roundtrip() {
    let original = User { id: 42, name: "Dave".to_string(), email: "dave@test.com".to_string(), active: true };
    let roundtripped = User::from_row(original.to_row());
    assert_eq!(original, roundtripped);
}
